import React, { useState, useEffect } from 'react';
import { Play, Pause, RotateCcw, X, Timer } from 'lucide-react';

const WORK_TIME = 25 * 60;
const BREAK_TIME = 5 * 60;

const FocusTimer = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [timeLeft, setTimeLeft] = useState(WORK_TIME);
  const [isActive, setIsActive] = useState(false);
  const [mode, setMode] = useState('work'); // 'work' or 'break'

  useEffect(() => {
    let interval = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => setTimeLeft(t => t - 1), 1000);
    } else if (isActive && timeLeft === 0) {
      if (mode === 'work') {
        setMode('break');
        setTimeLeft(BREAK_TIME);
        alert(`Focus complete! Starting 5 minute Break.`);
      } else {
        setMode('work');
        setTimeLeft(WORK_TIME);
        alert(`Break complete! Let's get back to Focus.`);
      }
      setIsActive(false);
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode]);

  const toggleTimer = () => setIsActive(!isActive);

  const resetTimer = () => {
    setIsActive(false);
    setTimeLeft(mode === 'work' ? WORK_TIME : BREAK_TIME);
  };

  const switchMode = (m) => {
    setIsActive(false);
    setMode(m);
    setTimeLeft(m === 'work' ? WORK_TIME : BREAK_TIME);
  };

  const formatTime = (seconds) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-8 right-8 p-4 bg-indigo-600 text-white rounded-full shadow-xl hover:bg-indigo-700 hover:scale-105 transition-all z-50 flex items-center justify-center group"
      >
        <Timer className="w-7 h-7" />
        <span className="max-w-0 overflow-hidden group-hover:max-w-xs transition-all duration-300 ease-in-out whitespace-nowrap group-hover:ml-3 font-semibold text-lg">Focus</span>
      </button>
    );
  }

  return (
    <div className="fixed bottom-8 right-8 w-80 bg-white rounded-3xl shadow-2xl border border-gray-100 z-50 overflow-hidden transform transition-all">
      <div className="flex justify-between items-center p-5 bg-gray-50 border-b border-gray-100">
        <h3 className="font-bold text-gray-700 flex items-center">
          <Timer className="w-5 h-5 mr-2 text-indigo-500" /> Pomodoro Timer
        </h3>
        <button onClick={() => setIsOpen(false)} className="text-gray-400 hover:text-red-500 transition-colors p-1 rounded-full hover:bg-red-50">
          <X className="w-5 h-5" />
        </button>
      </div>

      <div className="p-6">
        <div className="flex justify-center space-x-3 mb-8">
          <button 
            onClick={() => switchMode('work')}
            className={`px-5 py-2 rounded-full text-sm font-bold transition-all ${mode === 'work' ? 'bg-red-100 text-red-600 scale-105 shadow-sm' : 'bg-gray-100 text-gray-500 hover:bg-gray-200'}`}
          >
            Focus
          </button>
          <button 
            onClick={() => switchMode('break')}
            className={`px-5 py-2 rounded-full text-sm font-bold transition-all ${mode === 'break' ? 'bg-green-100 text-green-600 scale-105 shadow-sm' : 'bg-gray-100 text-gray-500 hover:bg-gray-200'}`}
          >
            Break
          </button>
        </div>

        <div className="flex justify-center mb-8">
          <span className={`text-6xl font-black font-mono tracking-tighter ${mode === 'work' ? 'text-red-500' : 'text-green-500'}`}>
            {formatTime(timeLeft)}
          </span>
        </div>

        <div className="flex justify-center space-x-6">
          <button 
            onClick={toggleTimer}
            className={`flex items-center justify-center p-4 rounded-full text-white shadow-lg transition-transform hover:scale-105 ${isActive ? 'bg-amber-500' : 'bg-indigo-600'}`}
          >
            {isActive ? <Pause className="w-8 h-8" /> : <Play className="w-8 h-8 ml-1" />}
          </button>
          <button 
            onClick={resetTimer}
            className="flex items-center justify-center p-4 rounded-full bg-gray-100 text-gray-600 hover:bg-gray-200 transition-transform hover:scale-105 shadow-sm"
          >
            <RotateCcw className="w-7 h-7" />
          </button>
        </div>
      </div>
    </div>
  );
};

export default FocusTimer;

import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { LayoutDashboard, Menu, X, Users, StickyNote, CheckSquare, Folder, BarChart, Settings } from 'lucide-react';

const Navigation = ({ isMobileMenuOpen, setIsMobileMenuOpen, onOpenSettings }) => {
  const { user, logout } = useAuth();
  const location = useLocation();

  if (!user) return null; // Don't show nav on login page

  const navItems = [
    { name: 'Dashboard', icon: LayoutDashboard, path: '/' },
    { name: 'Notes', icon: StickyNote, path: '/notes' },
    { name: 'Tasks', icon: CheckSquare, path: '/tasks' },
    { name: 'Routines', icon: Folder, path: '/routines' },
    { name: 'Group', icon: Users, path: '/flatmanager' },
    { name: 'Reports', icon: BarChart, path: '/reports' },
  ];

  const currentPath = location.pathname;

  return (
    <>
      {/* Desktop Sidebar */}
      <div className={`fixed inset-y-0 left-0 z-40 w-64 bg-white dark:bg-gray-900 border-r border-gray-100 dark:border-gray-800 transform transition-transform duration-300 ease-in-out flex flex-col sm:relative sm:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0 shadow-xl' : '-translate-x-full'}`}>

        <div className="p-6 flex items-center justify-between sm:justify-start">
          <div className="flex items-center">
            {/* Hexagon Logo approximation */}
            <img src="/logo.png" className="w-8 h-8 dark:invert-0 invert mr-2" />
            <span className="text-xl font-bold text-gray-900 dark:text-gray-100 tracking-tight">OmniFlow</span>
          </div>
          <button onClick={() => setIsMobileMenuOpen(false)} className="sm:hidden text-gray-400 hover:text-gray-600 dark:hover:text-gray-200">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="flex-1 px-4 py-4 space-y-1 overflow-y-auto hide-scrollbar">
          {navItems.map((item) => {
            const isActive = currentPath === item.path || (item.path !== '/' && currentPath.startsWith(item.path));
            return (
              <Link
                key={item.name}
                to={item.path}
                onClick={() => setIsMobileMenuOpen(false)}
                className={`group flex items-center px-3 py-2.5 rounded-lg font-medium text-sm transition-colors ${isActive
                  ? 'bg-black dark:bg-white text-white dark:text-black shadow-md'
                  : 'text-gray-500 hover:text-gray-900 hover:bg-gray-50 dark:text-gray-400 dark:hover:text-gray-100 dark:hover:bg-gray-800'
                  }`}
              >
                <item.icon
                  className={`w-5 h-5 mr-3 transition-colors ${isActive
                    ? 'text-white dark:text-black'
                    : 'text-gray-400 group-hover:text-gray-900 dark:group-hover:text-gray-100'
                    }`}
                />
                {item.name}
              </Link>
            );
          })}
        </div>

        {/* Bottom Section */}
        <div className="p-4 border-t border-gray-50 space-y-1 dark:border-gray-800">
          <button
            onClick={() => {
              setIsMobileMenuOpen(false);
              onOpenSettings();
            }}
            className="group w-full flex items-center px-3 py-2.5 rounded-lg text-sm font-medium text-gray-500 hover:text-gray-900 hover:bg-gray-50 transition-colors dark:text-gray-400 dark:hover:text-gray-100 dark:hover:bg-gray-800"
          >
            <Settings className="w-5 h-5 mr-3 text-gray-400 transition-colors group-hover:text-gray-900 dark:group-hover:text-gray-100" />
            Settings
          </button>
        </div>
      </div>

      {/* Mobile menu backdrop */}
      {isMobileMenuOpen && (
        <div
          className="fixed inset-0 z-30 bg-gray-900/20 backdrop-blur-sm sm:hidden transition-opacity"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}
    </>
  );
};

export default Navigation;

